<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller; use App\Http\Requests\Admin\SeatLayoutRequest; use App\Models\SeatLayout; use Illuminate\Support\Arr; use Illuminate\Support\Facades\DB;
class SeatLayoutController extends Controller { public function index(){ $this->authorize('manage',SeatLayout::class); return view('admin.seat-layouts.index',['layouts'=>SeatLayout::withCount('seats')->latest()->paginate(15)]); } public function create(){ $this->authorize('manage',SeatLayout::class); return view('admin.seat-layouts.form',['layout'=>null]); } public function store(SeatLayoutRequest $r){ DB::transaction(function() use($r){ $layout=SeatLayout::create(Arr::only($r->validated(), ['name','rows','columns','status'])); $this->syncSeats($layout,$r->input('blocked_seats',[])); }); return redirect()->route('admin.seat-layouts.index'); } public function edit(SeatLayout $seat_layout){ $this->authorize('manage',SeatLayout::class); return view('admin.seat-layouts.form',['layout'=>$seat_layout->load('seats')]); } public function update(SeatLayoutRequest $r, SeatLayout $seat_layout){ DB::transaction(function() use($r,$seat_layout){ $seat_layout->update(Arr::only($r->validated(), ['name','rows','columns','status'])); $seat_layout->seats()->delete(); $this->syncSeats($seat_layout,$r->input('blocked_seats',[])); }); return redirect()->route('admin.seat-layouts.index'); } public function destroy(SeatLayout $seat_layout){ $this->authorize('manage',SeatLayout::class); $seat_layout->delete(); return back(); } private function syncSeats(SeatLayout $layout,array $blocked): void { for($row=1;$row<=$layout->rows;$row++) for($col=1;$col<=$layout->columns;$col++){ $num=chr(64+$row).$col; $layout->seats()->create(['seat_number'=>$num,'row_number'=>$row,'column_number'=>$col,'is_blocked'=>in_array($num,$blocked)]); } } }
